def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        elif ratio == 1:
            priorities[i] = 0
            continue
        score = 0
        for j in range(1, 16):
            if j % 2 == 0:
                term = (ratio ** j) / (j * 2)
            else:
                term = -((ratio ** j) / j)
            score += term
        adjustment = 1.0
        if capacity < item * 1.5:
            adjustment *= 2.0
        elif capacity < item * 2:
            adjustment *= 1.5
        elif capacity < item * 3:
            adjustment *= 1.2
        penalty = 0
        for k in range(i, min(n, i+3)):
            if bins[k] != 0:
                overlap_ratio = item / bins[k]
                if 0 < overlap_ratio < 1:
                    penalty += (1 - overlap_ratio) ** 2
        penalty = penalty / 3
        score = -score * adjustment + penalty
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
